def sum_to_n(n: int):
    if n >= 0:
        # Sum of integers from 0 to n (inclusive)
        # This is the arithmetic series sum formula for 1 to n,
        # where adding 0 does not change the sum.
        return n * (n + 1) // 2
    else:
        # For n < 0, the sum is 0 + (-1) + ... + n.
        # This is equivalent to - (1 + 2 + ... + |n|).
        # Calculate sum of 1 to |n|, then negate it.
        abs_n = abs(n)
        return -(abs_n * (abs_n + 1) // 2)

