def fix_spaces(text):
    words = text.split()

    if not words:
        return ""

    result_parts = []

    for i, word in enumerate(words):
        result_parts.append(word)

        # If it's not the last word, add a separator based on the current word's length
        if i < len(words) - 1:
            if len(word) > 2:
                result_parts.append('-')
            else:
                result_parts.append('_')

    return "".join(result_parts)

def fix_spaces(text):
    result = []
    i = 0
    n = len(text)

    while i < n:
        if text[i] == ' ':
            # Found a space, count consecutive spaces
            space_count = 0
            while i < n and text[i] == ' ':
                space_count += 1
                i += 1

            # Apply rules based on space_count
            if space_count > 2:
                result.append('-')
            elif space_count >= 2:  # This covers exactly 2 spaces
                result.append('_')
            else:  # This covers exactly 1 space
                result.append(' ')
        else:
            # Not a space, append character as is
            result.append(text[i])
            i += 1

    return "".join(result)

def fix_spaces(text):
    result_parts = []
    i = 0
    n = len(text)

    while i < n:
        if text[i] == ' ':
            # Found the start of a sequence of spaces
            space_start_idx = i
            space_end_idx = i
            while space_end_idx < n and text[space_end_idx] == ' ':
                space_end_idx += 1

            space_count = space_end_idx - space_start_idx

            if space_count > 2:
                result_parts.append('-')
            elif space_count >= 1: # Covers 1 or 2 consecutive spaces
                result_parts.append('_')

            # Move the main index 'i' past the sequence of spaces that were just processed
            i = space_end_idx
        else:
            # Not a space, append the character as is
            result_parts.append(text[i])
            i += 1

    return "".join(result_parts)

def fix_spaces(text):
    result = []
    space_count = 0

    for char in text:
        if char == ' ':
            space_count += 1
        else:
            # If a non-space character is encountered, process any accumulated spaces
            if space_count > 2:
                result.append('-')
            elif space_count == 2:
                result.append('  ')
            elif space_count == 1:
                result.append(' ')

            # Reset space count and add the current non-space character
            space_count = 0
            result.append(char)

    # After the loop, handle any trailing spaces
    if space_count > 2:
        result.append('-')
    elif space_count == 2:
        result.append('  ')
    elif space_count == 1:
        result.append(' ')

    return "".join(result)

