def x_or_y(n, x, y):
    if n == 1:
        return y
    # The loop iterates through numbers from 2 up to n-1 (exclusive of n).
    # If n is divisible by any number in this range, it means n is composite
    # (for n > 1), and y is returned.
    for i in range(2, n):
        if n % i == 0:
            return y
    # If the loop completes, it means n was not divisible by any number in the
    # range [2, n-1]. This implies that n is a prime number (for n > 1),
    # and x is returned.
    return x

def x_or_y(n, x, y):
    if n <= 1:
        return y  # Numbers less than or equal to 1 are not prime
    for i in range(2, n):
        if n % i == 0:
            return y  # n is divisible by i, so n is not prime
    return x  # No divisors found, so n is prime

