def fix_spaces(text):
    result = []
    current_space_count = 0

    for char in text:
        if char == ' ':
            current_space_count += 1
        else:
            # If there were consecutive spaces before this non-space character
            if current_space_count > 2:
                result.append('-')
            elif current_space_count > 0:
                # current_space_count is 1 or 2
                result.append('_' * current_space_count)

            # Add the current non-space character
            result.append(char)

            # Reset space count for the next sequence
            current_space_count = 0

    # After the loop, check if there are any trailing spaces
    if current_space_count > 2:
        result.append('-')
    elif current_space_count > 0:
        # current_space_count is 1 or 2
        result.append('_' * current_space_count)

    return "".join(result)

