    def count_set_bits(n):
        # Handle negative numbers appropriately if they can occur.
        # bin() for negative numbers includes a '-' sign (e.g., bin(-5) is '-0b101').
        # The '1's count is usually for the magnitude or two's complement.
        # For simplicity and common interpretation of 'set bits' in such problems,
        # we'll count '1's in the string representation provided by bin().
        # This means for -5 (which is '-0b101'), count('1') will be 2.
        return bin(n).count('1')

