def fix_spaces(text):
    """
    Replaces consecutive spaces in the text based on their length:
    one or two spaces are converted to an equal number of underscores,
    while three or more spaces are replaced with a single hyphen.
    """
    def replace_func(match):
        num_spaces = len(match.group(0))
        if num_spaces == 1:
            return '_'
        elif num_spaces == 2:
            return '__'
        else: # num_spaces >= 3
            return '-'

    return re.sub(r' {1,}', replace_func, text)

