    if n <= 1:
        return factors

    # Handle factor 2
    while n % 2 == 0:
        factors.append(2)
        n //= 2

    # Handle odd factors
    # Start from 3 and increment by 2
    i = 3
    while i * i <= n:
        while n % i == 0:
            factors.append(i)
            n //= i
        i += 2

    # If n is still greater than 2, then n itself must be a prime factor
    if n > 2:
        factors.append(n)

    return factors

