    If there are one or two consecutive spaces, it replaces them with an underscore.
    """
    def _replacer(match):
        spaces_count = len(match.group(0))
        if spaces_count > 2:
            return '-'
        else: # spaces_count == 1 or spaces_count == 2
            return '_'

    return re.sub(r' +', _replacer, text)

