                space_start_idx = i  # Mark the beginning of a new space sequence
        else:  # char is a non-space character
            if space_start_idx != -1:  # We just finished a sequence of spaces
                space_length = i - space_start_idx
                if space_length >= 3:
                    result_parts.append('-')
                elif space_length == 2:
                    result_parts.append('_')
                elif space_length == 1:
                    result_parts.append(' ')  # Preserve single spaces not explicitly covered by replacement rules
                space_start_idx = -1  # Reset for the next sequence

            result_parts.append(char)  # Append the current non-space character

    # After the loop, check if there's an unhandled sequence of spaces at the end of the string
    if space_start_idx != -1:
        space_length = len(text) - space_start_idx
        if space_length >= 3:
            result_parts.append('-')
        elif space_length == 2:
            result_parts.append('_')
        elif space_length == 1:
            result_parts.append(' ')  # Preserve single trailing spaces

    return "".join(result_parts)

