def x_or_y(n, x, y):
    import math

    # A number is prime if it is greater than 1
    # and has no positive divisors other than 1 and itself.
    is_prime_num = True
    if n <= 1:
        is_prime_num = False
    elif n == 2:
        is_prime_num = True
    elif n % 2 == 0:  # All other even numbers are not prime
        is_prime_num = False
    else:
        # Check for odd divisors from 3 up to the square root of n
        # We only need to check up to sqrt(n) because if n has a divisor
        # greater than sqrt(n), it must also have a divisor smaller than sqrt(n).
        limit = int(math.sqrt(n)) + 1
        for i in range(3, limit, 2):
            if n % i == 0:
                is_prime_num = False
                break

    if is_prime_num:
        return y
    else:
        return x

def x_or_y(n, x, y):
