    elif n % 2 == 0:  # Even numbers greater than 2 are not prime
        is_n_prime = False
    else:
        # Check for odd divisors from 3 up to the square root of n
        is_n_prime = True
        i = 3
        while i * i <= n:
            if n % i == 0:
